mapper.select:
SELECT COUNT(1)
  FROM CONTENT_REVIEW
 WHERE MEMBER_NO = #{memberNo}
   AND CONTENTID = #{contentId}
   AND CREATE_DT >= TRUNC(SYSDATE, 'IW')
   AND CREATE_DT  < TRUNC(SYSDATE, 'IW') + 7

mapper.update:
UPDATE CONTENT_REVIEW
   SET REVIEW_COMMENT = #{reviewComment}
     , RATING         = #{rating}
 WHERE CONTENT_REVIEW_NO = #{contentReviewNo}
   AND MEMBER_NO         = #{memberNo}
   AND BLIND_YN          = 'N'

mapper.delete:
